css:
.loader {color: var(--loader-color, #ca8a04);
  --loader-secondary-color: #fde047;
  --loader-bg: #ffffff;
  width: 60px;
  aspect-ratio: 1;
  display: flex;
  animation: l12-0 4s infinite linear .5s;
}.loader::before,.loader::after {content: "";
  flex: 1;
  background: var(--loader-secondary-color, #fde047);
  clip-path: polygon(100% 0,100% 100%,0 50%);
  animation: l12-1 1s infinite linear;
}.loader::after {transform: scale(-1);
  animation:none;
}@keyframes l12-0 {0% ,12.49% {transform: rotate(0deg)}12.5%,37.49% {transform: rotate(90deg)}37.5%,62.49% {transform: rotate(180deg)}62.5%,87.49% {transform: rotate(270deg)}87.5%,100% {transform: rotate(360deg)}}@keyframes l12-1 {0%,5% {transform: translate(0px) perspective(150px) rotateY(0deg) }33% {transform: translate(-10px) perspective(150px) rotateX(0deg) }66% {transform: translate(-10px) perspective(150px) rotateX(-180deg)}95%,100%{transform: translate(0px) perspective(150px) rotateX(-180deg)}}
